#!/usr/bin/env python3
"""Find the collision point between two Kalman-smoothed trajectories.

This script reads the JSON output generated by ``traj_recon.py`` after the
Kalman filtering + RTS smoothing stage (``kalman_smoothed_*.mp4_results.json``),
extracts the 3D positions of every tracked vehicle, and computes the closest
approach between each pair of trajectories. The minimal-distance frame is
reported as the collision point.

Example:
    python detect_collision_point.py \
        --kalman-json savepath/VV_209/kalman_smoothed_VV_209.mp4_results.json \
        --output savepath/VV_209/collision_point.json
"""

from __future__ import annotations

import argparse
import json
import math
import os
from dataclasses import dataclass
from typing import Dict, List, Optional, Sequence, Tuple

import numpy as np


@dataclass(frozen=True)
class TrajectoryPoint:
    frame: int
    position: np.ndarray  # shape (3,)


@dataclass
class ClosestApproach:
    tracking_id_a: int
    tracking_id_b: int
    distance: float
    frame_a: int
    frame_b: int
    position_a: np.ndarray
    position_b: np.ndarray

    @property
    def collision_frame(self) -> Optional[int]:
        """Return the shared frame index when both detections exist simultaneously."""
        return self.frame_a if self.frame_a == self.frame_b else None

    @property
    def mid_point(self) -> np.ndarray:
        """Approximate collision point as midpoint between the two closest positions."""
        return (self.position_a + self.position_b) / 2.0

    @property
    def frame_gap(self) -> int:
        """Frame index difference between the two closest detections."""
        return abs(self.frame_a - self.frame_b)


def load_trajectories(json_path: str) -> Dict[int, List[TrajectoryPoint]]:
    """Load Kalman-smoothed detections grouped by tracking ID."""
    with open(json_path, "r") as f:
        data = json.load(f)

    trajectories: Dict[int, List[TrajectoryPoint]] = {}

    for frame_key, detections in data.items():
        try:
            frame_idx = int(frame_key)
        except ValueError:
            # Skip non-integer keys just in case
            continue

        for det in detections:
            tracking_id = det.get("tracking_id")
            loc = det.get("loc")

            if tracking_id is None or loc is None:
                continue
            if not isinstance(loc, Sequence) or len(loc) != 3:
                continue

            position = np.asarray(loc, dtype=float)
            point = TrajectoryPoint(frame=frame_idx, position=position)
            trajectories.setdefault(int(tracking_id), []).append(point)

    for points in trajectories.values():
        points.sort(key=lambda p: p.frame)

    return trajectories


def _closest_same_frame(
    tracking_id_a: int,
    traj_a: List[TrajectoryPoint],
    tracking_id_b: int,
    traj_b: List[TrajectoryPoint],
) -> Optional[ClosestApproach]:
    """Return closest approach using frames where both detections exist."""
    frame_to_pos_a = {pt.frame: pt.position for pt in traj_a}
    frame_to_pos_b = {pt.frame: pt.position for pt in traj_b}
    common_frames = sorted(set(frame_to_pos_a) & set(frame_to_pos_b))

    best: Optional[ClosestApproach] = None

    for frame in common_frames:
        pos_a = frame_to_pos_a[frame]
        pos_b = frame_to_pos_b[frame]
        dist = float(np.linalg.norm(pos_a - pos_b))

        if best is None or dist < best.distance:
            best = ClosestApproach(
                tracking_id_a=tracking_id_a,
                tracking_id_b=tracking_id_b,
                distance=dist,
                frame_a=frame,
                frame_b=frame,
                position_a=pos_a,
                position_b=pos_b,
            )

    return best


def _closest_any_frame(
    tracking_id_a: int,
    traj_a: List[TrajectoryPoint],
    tracking_id_b: int,
    traj_b: List[TrajectoryPoint],
) -> Optional[ClosestApproach]:
    """Return closest approach between two trajectories (any frames)."""
    if not traj_a or not traj_b:
        return None

    positions_a = np.stack([pt.position for pt in traj_a])
    positions_b = np.stack([pt.position for pt in traj_b])
    frames_a = np.array([pt.frame for pt in traj_a], dtype=int)
    frames_b = np.array([pt.frame for pt in traj_b], dtype=int)

    # Compute full distance matrix and locate minimum
    diff = positions_a[:, None, :] - positions_b[None, :, :]
    distances = np.linalg.norm(diff, axis=2)
    min_idx = np.unravel_index(np.argmin(distances), distances.shape)
    i, j = min_idx

    return ClosestApproach(
        tracking_id_a=tracking_id_a,
        tracking_id_b=tracking_id_b,
        distance=float(distances[i, j]),
        frame_a=int(frames_a[i]),
        frame_b=int(frames_b[j]),
        position_a=positions_a[i],
        position_b=positions_b[j],
    )


def compute_closest_approach(
    tracking_id_a: int,
    traj_a: List[TrajectoryPoint],
    tracking_id_b: int,
    traj_b: List[TrajectoryPoint],
) -> Optional[ClosestApproach]:
    """Compute closest approach, preferring shared-frame distances."""
    if not traj_a or not traj_b:
        return None

    same_frame_candidate = _closest_same_frame(tracking_id_a, traj_a, tracking_id_b, traj_b)

    if same_frame_candidate is not None:
        return same_frame_candidate

    return _closest_any_frame(tracking_id_a, traj_a, tracking_id_b, traj_b)


def summarize_result(result: ClosestApproach) -> Dict[str, object]:
    """Convert the result into basic Python types for optional JSON output."""
    return {
        "tracking_id_a": result.tracking_id_a,
        "tracking_id_b": result.tracking_id_b,
        "closest_distance": result.distance,
        "frame_a": result.frame_a,
        "frame_b": result.frame_b,
        "collision_frame": result.collision_frame,
        "frame_gap": result.frame_gap,
        "position_a": result.position_a.tolist(),
        "position_b": result.position_b.tolist(),
        "collision_point_estimate": result.mid_point.tolist(),
    }


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Detect the closest approach between Kalman-smoothed trajectories.",
    )
    parser.add_argument(
        "--kalman-json",
        required=True,
        help="Path to kalman_smoothed_*.mp4_results.json produced by traj_recon.py",
    )
    parser.add_argument(
        "--output",
        help="Optional path to write the closest-approach data as JSON",
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()

    if not os.path.exists(args.kalman_json):
        raise FileNotFoundError(f"Kalman result not found: {args.kalman_json}")

    trajectories = load_trajectories(args.kalman_json)
    if len(trajectories) < 2:
        raise ValueError(
            "Need at least two trajectories in the Kalman results to detect a collision",
        )

    results: List[ClosestApproach] = []
    tracking_ids = sorted(trajectories.keys())

    for idx_a in range(len(tracking_ids)):
        for idx_b in range(idx_a + 1, len(tracking_ids)):
            tid_a = tracking_ids[idx_a]
            tid_b = tracking_ids[idx_b]
            result = compute_closest_approach(tid_a, trajectories[tid_a], tid_b, trajectories[tid_b])
            if result is not None:
                results.append(result)

    if not results:
        raise RuntimeError("Failed to compute any closest-approach pair")

    best = min(results, key=lambda r: r.distance)

    print("Closest approach summary:")
    print(f"  Tracking IDs: {best.tracking_id_a} vs {best.tracking_id_b}")
    print(f"  Closest distance: {best.distance:.3f} meters")
    if best.collision_frame is not None:
        print(f"  Collision frame: {best.collision_frame}")
    else:
        print(f"  Frame A: {best.frame_a}, Frame B: {best.frame_b} (gap {best.frame_gap})")
    print(f"  Position A: {best.position_a.tolist()}")
    print(f"  Position B: {best.position_b.tolist()}")
    print(f"  Estimated impact point: {best.mid_point.tolist()}")

    if args.output:
        output_payload = {
            "kalman_json": os.path.abspath(args.kalman_json),
            "closest_approach": summarize_result(best),
            "all_pairs": [summarize_result(res) for res in results],
        }
        with open(args.output, "w") as f:
            json.dump(output_payload, f, indent=2)
        print(f"\nSaved closest-approach details to {args.output}")


if __name__ == "__main__":
    main()
